// ─── Bio Age Chart ─────────────────────────────────────────────────────────
const BioAgeChart = () => {
  const [hovered, setHovered] = useState(null);
  const W = 540, H = 210;
  const padL = 52, padR = 44, padT = 24, padB = 44;
  const chartW = W - padL - padR, chartH = H - padT - padB;
  const minY = 28, maxY = 48;
  const toX = (i) => padL + (i / (BIO_AGE_DATA.length - 1)) * chartW;
  const toY = (v) => padT + chartH - ((v - minY) / (maxY - minY)) * chartH;
  const calPts = BIO_AGE_DATA.map((d, i) => `${toX(i)},${toY(d.calendar)}`).join(" ");
  const bioPts = BIO_AGE_DATA.map((d, i) => `${toX(i)},${toY(d.bio)}`).join(" ");
  const fillPts = [
    ...BIO_AGE_DATA.map((d, i) => `${toX(i)},${toY(d.calendar)}`),
    ...BIO_AGE_DATA.map((d, i) => `${toX(BIO_AGE_DATA.length-1-i)},${toY(BIO_AGE_DATA[BIO_AGE_DATA.length-1-i].bio)}`),
  ].join(" ");

  return (
    <div>
      <svg width="100%" viewBox={`0 0 ${W} ${H}`} style={{ overflow: "visible" }}>
        {[30,35,40,45].map(v => (
          <g key={v}>
            <line x1={padL} y1={toY(v)} x2={W-padR} y2={toY(v)} stroke={C.border} strokeWidth={1} strokeDasharray="3,3" />
            <text x={padL-8} y={toY(v)+4} textAnchor="end" fontSize={9} fill={C.muted}>{v}</text>
          </g>
        ))}
        <line x1={padL} y1={toY(44.5)} x2={W-padR} y2={toY(44.5)} stroke={C.muted} strokeWidth={1} strokeDasharray="6,3" opacity={0.4} />
        <text x={W-padR+6} y={toY(44.5)+4} fontSize={9} fill={C.muted}>44.5</text>
        <polygon points={fillPts} fill={C.green} opacity={0.07} />
        <polyline points={calPts} fill="none" stroke={C.muted} strokeWidth={1.5} strokeDasharray="4,3" strokeLinecap="round" opacity={0.5} />
        <polyline points={bioPts} fill="none" stroke={C.green} strokeWidth={2.5} strokeLinecap="round" strokeLinejoin="round" />
        {BIO_AGE_DATA.map((d, i) => (
          <circle key={`c${i}`} cx={toX(i)} cy={toY(d.calendar)} r={3} fill={C.muted} opacity={0.4} />
        ))}
        {BIO_AGE_DATA.map((d, i) => (
          <g key={`b${i}`} onMouseEnter={() => setHovered(i)} onMouseLeave={() => setHovered(null)} style={{ cursor: "pointer" }}>
            <circle cx={toX(i)} cy={toY(d.bio)} r={hovered===i ? 7 : 5} fill={C.green} stroke="#fff" strokeWidth={2} />
            <text x={toX(i)} y={toY(d.bio)-13} textAnchor="middle" fontSize={11} fontWeight={700} fill={C.green}>{d.bio}</text>
            {hovered===i && (
              <g>
                <rect x={toX(i)-52} y={toY(d.bio)-50} width={104} height={32} rx={6} fill={C.navy} />
                <text x={toX(i)} y={toY(d.bio)-38} textAnchor="middle" fontSize={9} fill="rgba(255,255,255,0.6)">{d.date} · Calendar {d.calendar}</text>
                <text x={toX(i)} y={toY(d.bio)-25} textAnchor="middle" fontSize={12} fontWeight={700} fill={C.green}>Bio {d.bio} · {d.gap} yrs</text>
              </g>
            )}
          </g>
        ))}
        {BIO_AGE_DATA.map((d, i) => (
          <text key={`xl${i}`} x={toX(i)} y={H-8} textAnchor="middle" fontSize={10} fill={C.muted} fontWeight={600}>{d.date}</text>
        ))}
      </svg>
      <div style={{ display: "flex", gap: 20, marginTop: 4 }}>
        {[
          { color: C.green, dash: false, label: "Biological Age" },
          { color: C.muted, dash: true, label: "Calendar Age" },
          { color: C.green, fill: true, label: "Youth Gap" },
        ].map((l, i) => (
          <div key={i} style={{ display: "flex", alignItems: "center", gap: 6 }}>
            {l.fill
              ? <div style={{ width: 16, height: 8, background: C.green, borderRadius: 2, opacity: 0.2 }} />
              : <svg width={20} height={3}><line x1={0} y1={1.5} x2={20} y2={1.5} stroke={l.color} strokeWidth={l.dash ? 1.5 : 2.5} strokeDasharray={l.dash ? "3,2" : "none"} opacity={l.dash ? 0.5 : 1} /></svg>
            }
            <span style={{ fontSize: 11, color: C.body }}>{l.label}</span>
          </div>
        ))}
      </div>
    </div>
  );
};

// ─── Reusable components ───────────────────────────────────────────────────
const Sparkline = ({ vals }) => {
  const valid = vals.filter(v => v !== null && typeof v === "number");
  if (valid.length < 2) return <span style={{ color: C.muted, fontSize: 11 }}>—</span>;
  const min = Math.min(...valid), max = Math.max(...valid), r = max - min || 1;
  const w = 56, h = 22;
  const pts = valid.map((v, i) => `${(i/(valid.length-1))*(w-4)+2},${h-2-((v-min)/r)*(h-4)}`).join(" ");
  const last = valid[valid.length-1], prev = valid[valid.length-2];
  const stroke = last < prev ? C.green : last > prev ? C.redAlert : C.muted;
  return (
    <svg width={w} height={h} style={{ verticalAlign: "middle" }}>
      <polyline points={pts} fill="none" stroke={stroke} strokeWidth="1.5" strokeLinecap="round" strokeLinejoin="round" />
      {valid.map((v, i) => {
        const x = (i/(valid.length-1))*(w-4)+2, y = h-2-((v-min)/r)*(h-4);
        return <circle key={i} cx={x} cy={y} r={i===valid.length-1?2.5:1.5} fill={i===valid.length-1?stroke:"#ccc"} />;
      })}
    </svg>
  );
};

const StatusDot = ({ flag }) => {
  const color = !flag ? C.green : (flag==="H"||flag==="↑") ? C.redAlert : (flag==="L"||flag==="↓") ? C.yellowWarn : C.blue;
  return <span style={{ display:"inline-block", width:8, height:8, borderRadius:"50%", background:color, boxShadow:`0 0 5px ${color}66`, flexShrink:0 }} />;
};

const FlagText = ({ val, flag }) => {
  if (val === null) return <span style={{ color: C.border }}>—</span>;
  const color = !flag ? C.body : (flag==="H"||flag==="↑") ? C.redAlert : (flag==="L"||flag==="↓") ? C.yellowWarn : C.blue;
  return <span style={{ color, fontWeight: flag ? 700 : 500, fontSize: 13 }}>{val}</span>;
};

const BioTable = ({ markers }) => (
  <div style={{ overflowX: "auto" }}>
    <table style={{ width: "100%", borderCollapse: "collapse", fontSize: 12 }}>
      <thead>
        <tr style={{ borderBottom: `2px solid ${C.border}` }}>
          {["Biomarker", "Target", ...DATES, "Trend", "Now"].map((h, i) => (
            <th key={i} style={{ ...S.label, padding: "8px 10px", textAlign: i<2?"left":"center", whiteSpace:"nowrap" }}>{h}</th>
          ))}
        </tr>
      </thead>
      <tbody>
        {markers.map((m, i) => {
          const latestIdx = [...m.vals].reverse().findIndex(v => v!==null);
          const latestFlag = latestIdx>=0 ? [...m.flags].reverse()[latestIdx] : null;
          return (
            <tr key={i} style={{ borderBottom:`1px solid ${C.border}` }}
              onMouseEnter={e=>e.currentTarget.style.background=C.cream}
              onMouseLeave={e=>e.currentTarget.style.background="transparent"}>
              <td style={{ padding:"11px 10px", color:C.navy, fontWeight:600, fontSize:13, fontFamily:"system-ui,sans-serif" }}>
                {m.name}
                <span style={{ display:"block", color:C.muted, fontSize:11, fontWeight:400 }}>{m.unit}</span>
              </td>
              <td style={{ padding:"11px 10px", color:C.muted, fontSize:12 }}>{m.target}</td>
              {m.vals.map((v, j) => (
                <td key={j} style={{ textAlign:"center", padding:"11px 8px" }}>
                  <FlagText val={v} flag={m.flags[j]} />
                </td>
              ))}
              <td style={{ textAlign:"center", padding:"11px 8px" }}><Sparkline vals={m.vals} /></td>
              <td style={{ textAlign:"center", padding:"11px 8px" }}><StatusDot flag={latestFlag} /></td>
            </tr>
          );
        })}
      </tbody>
    </table>
  </div>
);

const ScoreRing = ({ score, label, color, sub }) => {
  const r = 32, circ = 2*Math.PI*r, filled = (score/100)*circ;
  return (
    <div style={{ display:"flex", flexDirection:"column", alignItems:"center", gap:5 }}>
      <div style={{ position:"relative", width:80, height:80 }}>
        <svg width={80} height={80} style={{ transform:"rotate(-90deg)" }}>
          <circle cx={40} cy={40} r={r} fill="none" stroke={C.border} strokeWidth={6} />
          <circle cx={40} cy={40} r={r} fill="none" stroke={color} strokeWidth={6} strokeDasharray={`${filled} ${circ}`} strokeLinecap="round" />
        </svg>
        <div style={{ position:"absolute", inset:0, display:"flex", alignItems:"center", justifyContent:"center" }}>
          <span style={{ fontSize:20, fontWeight:700, color, fontFamily:"system-ui,sans-serif" }}>{score}</span>
        </div>
      </div>
      <span style={{ fontSize:10, fontWeight:700, color:C.navy, textTransform:"uppercase", letterSpacing:"0.08em", textAlign:"center", fontFamily:"system-ui,sans-serif" }}>{label}</span>
      {sub && <span style={{ fontSize:10, color:C.muted, textAlign:"center", maxWidth:80, fontFamily:"system-ui,sans-serif" }}>{sub}</span>}
    </div>
  );
};

